const body = $input.item.json.body || $input.item.json;

// Required metadata fields
const required = ['callId', 'repEmail', 'repName', 'contactEmail', 'contactName', 'companyName'];
const missing = required.filter(f => !body[f]);
if (missing.length > 0) {
  throw new Error(`Missing required call metadata: ${missing.join(', ')}`);
}

// Validate email formats
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!emailRegex.test(body.repEmail)) {
  throw new Error(`Invalid rep email: ${body.repEmail}`);
}
if (!emailRegex.test(body.contactEmail)) {
  throw new Error(`Invalid contact email: ${body.contactEmail}`);
}

// Validate audio URL or binary
const audioUrl = body.audioUrl || body.audio_url || null;
if (!audioUrl && !$input.item.binary?.audio) {
  throw new Error('No audio provided: supply audioUrl or binary audio attachment');
}

// Duration validation
const durationSecs = parseInt(body.callDurationSecs) || 0;
if (durationSecs > 7200) {
  throw new Error(`Call too long: ${durationSecs}s exceeds 2-hour maximum for processing`);
}

// Deal stage normalization
const validStages = ['prospecting', 'qualification', 'discovery', 'demo', 'proposal', 'negotiation', 'closed_won', 'closed_lost'];
const dealStage = body.dealStage?.toLowerCase().replace(/ /g, '_') || 'unknown';

// Build normalized call record
const callRecord = {
  callId: body.callId.trim(),
  repEmail: body.repEmail.trim().toLowerCase(),
  repName: body.repName.trim(),
  repManagerEmail: body.repManagerEmail || null,
  contactEmail: body.contactEmail.trim().toLowerCase(),
  contactName: body.contactName.trim(),
  companyName: body.companyName.trim(),
  dealStage: validStages.includes(dealStage) ? dealStage : 'unknown',
  dealValue: body.dealValue ? parseFloat(body.dealValue) : null,
  crmContactId: body.crmContactId || null,
  crmDealId: body.crmDealId || null,
  audioUrl,
  callDurationSecs: durationSecs,
  callDurationMins: Math.round(durationSecs / 60),
  callDate: body.callDate || new Date().toISOString(),
  language: body.language || 'en',
  product: body.product || 'General',
  notes: body.notes || null,
  processingId: `PROC-${Date.now()}-${Math.random().toString(36).substr(2, 8).toUpperCase()}`,
  receivedAt: new Date().toISOString(),
  status: 'VALIDATED'
};

return { json: { callRecord } };

const whisperResponse = $('Transcribe Audio with OpenAI Whisper').item.json;
const callRecord = $('Validate Call Metadata and Audio').item.json.callRecord;

// Validate transcription succeeded
if (!whisperResponse || whisperResponse.error) {
  throw new Error(`Whisper transcription failed: ${whisperResponse?.error?.message || 'Unknown error'}`);
}

const fullText = whisperResponse.text || '';
if (!fullText.trim()) {
  throw new Error('Transcription returned empty text. Audio may be silent or corrupted.');
}

// Extract segment-level data for analysis
const segments = whisperResponse.segments || [];
const totalDuration = whisperResponse.duration || callRecord.callDurationSecs;

// Calculate word count and speaking pace
const wordCount = fullText.split(/\s+/).filter(w => w.length > 0).length;
const wordsPerMinute = totalDuration > 0 ? Math.round((wordCount / totalDuration) * 60) : 0;

// Estimate speaker turns (basic heuristic: long pauses between segments)
const speakerTurns = segments.filter((seg, idx) => {
  if (idx === 0) return false;
  const gap = seg.start - segments[idx - 1].end;
  return gap > 1.5; // 1.5s gap = likely speaker change
}).length;

// Chunk transcript for GPT-4 (max 12k chars per chunk to stay in context)
const CHUNK_SIZE = 12000;
const chunks = [];
for (let i = 0; i < fullText.length; i += CHUNK_SIZE) {
  chunks.push(fullText.substring(i, i + CHUNK_SIZE));
}

return {
  json: {
    callRecord,
    transcript: {
      fullText,
      wordCount,
      wordsPerMinute,
      totalDurationSecs: totalDuration,
      segmentCount: segments.length,
      estimatedSpeakerTurns: speakerTurns,
      language: whisperResponse.language || callRecord.language,
      chunkCount: chunks.length,
      transcriptChunk: chunks[0], // primary chunk for GPT-4
      transcribedAt: new Date().toISOString()
    }
  }
};

