const aiResponse = $input.item.json;
let aiText = aiResponse.response || aiResponse.output || aiResponse.text || '';

if (aiResponse.content && Array.isArray(aiResponse.content)) {
  aiText = aiResponse.content[0]?.text || aiResponse.content[0]?.message?.content || '';
}

const cleanText = aiText.replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();

let intelligence;
try {
  intelligence = JSON.parse(cleanText);
} catch (e) {
  throw new Error(`Failed to parse GPT-4 call intelligence: ${e.message}. Raw: ${cleanText.substring(0, 300)}`);
}

const callData = $('Parse and Structure Transcript').item.json;
const crmResponse = $('Fetch CRM Contact History').item.json;

// Extract CRM contact ID if found
const crmContact = crmResponse?.results?.[0] || null;
const crmContactId = crmContact?.id || callData.callRecord.crmContactId || null;

return {
  json: {
    callRecord: callData.callRecord,
    transcript: callData.transcript,
    intelligence,
    crmContactId,
    crmContact,
    processedAt: new Date().toISOString()
  }
};

