    callIntelligence: {
      sentiment: data.intelligence.overallSentiment,
      sentimentScore: data.intelligence.sentimentScore,
      primaryIntent: data.intelligence.primaryIntent,
      dealRisk: data.intelligence.dealRisk,
      dealMomentum: data.intelligence.dealMomentum,
      buyingSignals: (data.intelligence.buyingSignals || []).length,
      objections: (data.intelligence.objections || []).length,
