      recommendedStage: data.intelligence.recommendedDealStage
    },
    repScorecard: data.intelligence.repScorecard,
    crmUpdated: true,
    crmContactId: data.crmContactId,
    summaryEmailSent: true,
    processedAt: data.processedAt
  }
};
